import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, CheckCircle2, AlertTriangle, Check, 
  RotateCcw, Trophy, Volume2, BookOpen, 
  BarChart3, ArrowLeft, Flag, ListChecks,
  ImageIcon, Filter, Map as MapIcon
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';
import { cleanImageUrl } from '../utils';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
  isEmbedded?: boolean;
  enableConfiguration?: boolean;
  onExit?: () => void;
  onImageClick?: (url: string) => void;
  mistakes?: string[]; 
  onAddMistake?: (id: string) => void; 
  onRemoveMistake?: (id: string) => void; 
}

const Quiz: React.FC<QuizProps> = ({ 
    data, 
    toggleHeader, 
    isEmbedded = false,
    onExit, 
    onImageClick,
    mistakes = [], 
    onAddMistake, 
    onRemoveMistake 
}) => {
  const [view, setView] = useState<'config' | 'playing' | 'summary' | 'results' | 'review'>('config');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [mode, setMode] = useState<'exam' | 'study' | 'vault' | 'atlas'>('exam');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [questionLimit, setQuestionLimit] = useState(25);

  // Professional Notification State
  const [notification, setNotification] = useState<{show: boolean, type: 'add' | 'remove'}>({ show: false, type: 'add' });

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [onlyDiagrams, setOnlyDiagrams] = useState(false);

  const { speak, isSpeaking, cancel, speakingId } = useSpeech();
  const scrollRef = useRef<HTMLDivElement>(null);

  // --- PERSISTENCE LOGIC ---
  useEffect(() => {
    if (isEmbedded) return; // Don't restore session if embedded

    const savedState = localStorage.getItem('ot_quiz_active_session');
    if (savedState) {
        try {
            const parsed = JSON.parse(savedState);
            // Only resume if we have valid data and we are in config mode
            if (view === 'config' && parsed.questions && parsed.questions.length > 0) {
                setQuestions(parsed.questions);
                setCurrentQIndex(parsed.currentQIndex);
                setTimeLeft(parsed.timeLeft);
                setMode(parsed.mode);
                setView(parsed.view);
                if (toggleHeader) toggleHeader(false);
            }
        } catch (e) {
            console.error("Failed to restore quiz session", e);
            localStorage.removeItem('ot_quiz_active_session');
        }
    }
  }, [isEmbedded]);

  // Save state on every change
  useEffect(() => {
    if (isEmbedded) return; // Don't save embedded sessions

    if (view === 'playing' || view === 'summary') {
        const stateToSave = {
            questions,
            currentQIndex,
            timeLeft,
            mode,
            view
        };
        localStorage.setItem('ot_quiz_active_session', JSON.stringify(stateToSave));
    } else if (view === 'results' || view === 'config') {
        localStorage.removeItem('ot_quiz_active_session');
    }
  }, [questions, currentQIndex, timeLeft, mode, view, isEmbedded]);

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const currentPool = useMemo(() => {
      let pool = data;

      if (mode === 'vault') {
          pool = pool.filter(q => mistakes.includes(q.id));
      } else if (mode === 'atlas') {
          pool = pool.filter(q => q.questionImage || q.answerImage);
      }

      if (selectedCategories.length > 0) {
          pool = pool.filter(q => selectedCategories.includes(q.category));
      }

      if (onlyDiagrams && mode !== 'atlas') {
          pool = pool.filter(q => q.questionImage || q.answerImage);
      }

      return pool;
  }, [mode, mistakes, selectedCategories, data, onlyDiagrams]);

  const currentPoolSize = currentPool.length;

  // Auto-start for embedded mode (Interactive Atlas)
  useEffect(() => {
    if (isEmbedded && view === 'config' && currentPoolSize > 0) {
        setMode('study');
        const prepared = [...currentPool]
            .map(q => ({
                id: q.id, 
                data: q,
                options: (q.options || [q.answerText]).sort(() => Math.random() - 0.5),
                correctOption: q.answerText, 
                userAnswer: null, 
                isFlagged: false
            } as QuizQuestion));

        setQuestions(prepared);
        setCurrentQIndex(0);
        setView('playing');
    }
  }, [isEmbedded, currentPoolSize]); // Only run when pool is ready

  useEffect(() => {
      if (currentPoolSize === 0) {
          setQuestionLimit(0);
      } else if (questionLimit > currentPoolSize) {
          setQuestionLimit(currentPoolSize);
      } else if (questionLimit === 0 && currentPoolSize > 0) {
          setQuestionLimit(Math.min(25, currentPoolSize));
      }
  }, [currentPoolSize, questionLimit]);

  const startSession = () => {
    if (currentPoolSize === 0) {
        if (mode === 'vault') {
             alert("Your Smart Review is empty! Great job mastering the content.");
        } else {
             alert("No questions available with the current filters.");
        }
        return;
    }

    const limit = Math.min(questionLimit, currentPoolSize);
    const prepared = [...currentPool]
        .sort(() => Math.random() - 0.5)
        .slice(0, limit)
        .map(q => ({
            id: q.id, 
            data: q,
            options: (q.options || [q.answerText]).sort(() => Math.random() - 0.5),
            correctOption: q.answerText, 
            userAnswer: null, 
            isFlagged: false
        } as QuizQuestion));

    setQuestions(prepared);
    setCurrentQIndex(0);
    setTimeLeft(prepared.length * 60); 
    setView('playing');
    if (toggleHeader) toggleHeader(false);
  };

  const restartQuiz = () => {
    localStorage.removeItem('ot_quiz_active_session');
    setView('config');
    setQuestions([]);
    if (toggleHeader) toggleHeader(true);
  };

  const toggleFlag = (index: number, e?: React.MouseEvent) => {
      e?.stopPropagation();
      setQuestions(prev => {
          const newQ = [...prev];
          newQ[index].isFlagged = !newQ[index].isFlagged;
          return newQ;
      });
  };

  const goToSummary = () => {
      setView('summary');
  };

  // --- IMMEDIATE MISTAKE SYSTEM LOGIC ---
  const handleOptionSelect = (option: string) => {
      const currentQ = questions[currentQIndex];

      // If already answered in Study/Vault mode, ignore click
      if ((mode === 'study' || mode === 'vault' || mode === 'atlas') && currentQ.userAnswer) return;

      const isCorrect = option === currentQ.correctOption;

      // 1. Update Local State
      setQuestions(prev => { 
          const c = [...prev]; 
          c[currentQIndex].userAnswer = option; 
          return c; 
      });

      // 2. Immediate Smart Review Update
      if (!isCorrect) {
          // If wrong, add to mistakes immediately
          onAddMistake?.(currentQ.id);

          // Show "Added" Notification
          setNotification({ show: true, type: 'add' });
          setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 2000);
      } 
      else if (isCorrect && mode === 'vault') {
          // If correct AND we are in Review Mode, remove it
          onRemoveMistake?.(currentQ.id);

          // Show "Removed/Mastered" Notification
          setNotification({ show: true, type: 'remove' });
          setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 2000);
      }
  };

  const handleFinish = () => {
    cancel();
    localStorage.removeItem('ot_quiz_active_session');

    // AUTOMATICALLY ADD UNANSWERED OR WRONG QUESTIONS TO MISTAKES
    questions.forEach(q => {
        const isWrongOrSkipped = q.userAnswer !== q.correctOption;
        if (isWrongOrSkipped) {
            onAddMistake?.(q.id);
        }
    });

    setView('results');
  };

  useEffect(() => {
    let timer: any;
    if ((view === 'playing' || view === 'summary') && mode === 'exam' && timeLeft > 0) {
      timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && (view === 'playing' || view === 'summary') && mode === 'exam') {
        handleFinish();
    }
    return () => clearInterval(timer);
  }, [timeLeft, view, mode]);

  // --- FILTER OPTIONS FOR MODAL ---
  const quizFilterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Questions',
        icon: ImageIcon,
        isActive: onlyDiagrams,
        onClick: () => setOnlyDiagrams(!onlyDiagrams),
        colorTheme: 'rose'
    }
  ];

  // --- VIEW: CONFIGURATION ---
  if (view === 'config') {
    const filtersActive = selectedCategories.length > 0 || (onlyDiagrams && mode !== 'atlas');

    return (
      <div className="h-full w-full flex items-center justify-center p-4 bg-slate-50/50 pb-32 md:pb-4">
          <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col max-h-[75vh] md:max-h-[90vh]">
            <div className="bg-slate-900 p-6 md:p-8 relative overflow-hidden shrink-0">
                <div className="relative z-10">
                    <h2 className="text-2xl md:text-3xl font-black text-white font-display tracking-tight">Exam Configuration</h2>
                    <p className="text-rose-500 text-xs font-bold uppercase tracking-[0.2em] mt-1">Anatomy and Physiology OT</p>
                </div>
                <div className="absolute right-0 top-0 w-64 h-64 bg-rose-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            </div>

            <div className="flex-1 p-6 md:p-8 space-y-4 overflow-y-auto custom-scrollbar">
                <div className="grid grid-cols-2 gap-3">
                    <button 
                        onClick={() => setMode('exam')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'exam' ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'exam' ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Clock size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'exam' ? 'text-rose-900' : 'text-slate-900'}`}>Exam</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Strict Timing</p>
                    </button>

                    <button 
                        onClick={() => setMode('study')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'study' ? 'border-indigo-200 bg-indigo-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'study' ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Zap size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'study' ? 'text-indigo-900' : 'text-slate-900'}`}>Study</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Instant Feedback</p>
                    </button>

                    <button 
                        onClick={() => setMode('vault')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'vault' ? 'border-amber-200 bg-amber-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'vault' ? 'bg-amber-100 text-amber-600' : 'bg-slate-50 text-slate-400'}`}>
                            <AlertTriangle size={18} />
                        </div>
                        <div className="flex justify-between items-center">
                            <h3 className={`font-bold text-sm ${mode === 'vault' ? 'text-amber-900' : 'text-slate-900'}`}>Smart Review</h3>
                            {mistakes.length > 0 && <span className="bg-amber-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-md">{mistakes.length}</span>}
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Fix Mistakes</p>
                    </button>

                    <button 
                        onClick={() => setMode('atlas')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'atlas' ? 'border-teal-200 bg-teal-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'atlas' ? 'bg-teal-100 text-teal-600' : 'bg-slate-50 text-slate-400'}`}>
                            <MapIcon size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'atlas' ? 'text-teal-900' : 'text-slate-900'}`}>Atlas Mode</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Visual Lab</p>
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <button 
                        onClick={() => setIsFilterOpen(true)}
                        className={`p-4 rounded-2xl border-2 text-left transition-all flex items-center justify-between group ${filtersActive ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-slate-50 hover:bg-white hover:border-slate-200'}`}
                    >
                        <div className="flex items-center gap-3 overflow-hidden">
                            <div className={`p-2 rounded-lg ${filtersActive ? 'bg-rose-100 text-rose-600' : 'bg-white border border-slate-200 text-slate-400 group-hover:text-rose-500'}`}>
                                <Filter size={16}/>
                            </div>
                            <div className="flex flex-col text-left min-w-0">
                                <span className={`text-[10px] font-black uppercase tracking-wider ${filtersActive ? 'text-rose-400' : 'text-slate-400'}`}>Filters</span>
                                <span className={`font-bold text-xs truncate ${filtersActive ? 'text-rose-900' : 'text-slate-700'}`}>
                                    {selectedCategories.length > 0 ? `${selectedCategories.length} Chapters` : 'Default Pool'}
                                </span>
                            </div>
                        </div>
                        <ChevronRight size={16} className={`${filtersActive ? 'text-rose-400' : 'text-slate-400'} group-hover:translate-x-1 transition-transform shrink-0`} />
                    </button>

                    <div className="p-4 rounded-2xl border border-slate-200 bg-slate-50 flex flex-col justify-center gap-2">
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Question Limit</span>
                            <span className="font-bold text-xs text-slate-900 bg-white px-2 py-1 rounded border border-slate-200">{questionLimit}</span>
                        </div>
                        <input 
                            type="range" 
                            min={Math.min(1, currentPoolSize)}
                            max={currentPoolSize} 
                            step="1" 
                            value={questionLimit || 0}
                            onChange={(e) => setQuestionLimit(parseInt(e.target.value))}
                            disabled={currentPoolSize === 0}
                            className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900 hover:accent-rose-600 transition-all"
                        />
                    </div>
                </div>
            </div>

            <div className="p-4 md:p-6 border-t border-slate-100 bg-white shrink-0">
                <button 
                    onClick={startSession}
                    disabled={currentPoolSize === 0}
                    className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-rose-600 transition-all shadow-xl hover:shadow-rose-200 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                    Start Exam <ChevronRight size={16} />
                </button>
            </div>
          </div>

          <FilterModal
            isOpen={isFilterOpen}
            onClose={() => setIsFilterOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => { setSelectedCategories([]); setOnlyDiagrams(false); }}
            mainOptions={quizFilterOptions}
            title="Exam Settings"
          />
      </div>
    );
  }

  // --- VIEW: PLAYING ---
  const currentQ = questions[currentQIndex];
  if (view === 'playing' && currentQ) {
    const isExam = mode === 'exam';
    const isStudy = mode === 'study' || mode === 'vault' || mode === 'atlas'; 
    const showFeedback = isStudy && currentQ.userAnswer; 

    return (
      <div className="h-full flex flex-col bg-white relative">

        {/* --- PROFESSIONAL NOTIFICATION --- */}
        {notification.show && (
            <div className="absolute top-20 left-0 right-0 flex justify-center z-50 pointer-events-none animate-in fade-in slide-in-from-top-4">
                <div className={`px-6 py-3 rounded-full shadow-2xl border-2 flex items-center gap-3 font-bold text-xs uppercase tracking-widest ${
                    notification.type === 'add' 
                    ? 'bg-rose-500 text-white border-white' 
                    : 'bg-emerald-500 text-white border-white'
                }`}>
                    {notification.type === 'add' ? (
                        <>
                            <AlertTriangle size={16} className="fill-current text-white" />
                            <span>Added to Smart Review</span>
                        </>
                    ) : (
                        <>
                            <CheckCircle2 size={16} className="fill-current text-white" />
                            <span>Mastered & Removed</span>
                        </>
                    )}
                </div>
            </div>
        )}

        <header className="h-14 md:h-16 glass border-b border-slate-100 flex items-center justify-between px-4 md:px-6 shrink-0 z-30">
            <div className="flex items-center gap-3 md:gap-4">
                <div className="w-8 h-8 md:w-10 md:h-10 bg-slate-900 text-white rounded-lg md:rounded-xl flex items-center justify-center font-black text-xs">
                    {currentQIndex + 1}
                </div>
                <div>
                    <h1 className="text-[10px] font-black uppercase text-slate-400 tracking-widest leading-none hidden md:block">
                        {isExam ? 'Assessment' : 'Study'}
                    </h1>
                    <p className="text-xs font-bold text-slate-900 truncate max-w-[120px] md:max-w-none">Anatomy and Physiology OT</p>
                </div>
            </div>
            <div className="flex items-center gap-2 md:gap-3">

                <button 
                    onClick={goToSummary}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-white border border-slate-200 text-slate-600 rounded-lg md:rounded-xl font-bold text-[10px] md:text-xs uppercase tracking-wider hover:bg-slate-50 hover:text-slate-900 transition-all shadow-sm"
                    title="Finish Exam Immediately"
                >
                    <ListChecks size={16} className="text-emerald-500" />
                    <span className="hidden sm:inline">Submit</span>
                </button>

                {isExam && (
                    <div className="px-3 py-1.5 md:px-4 md:py-2 bg-rose-50 text-rose-600 rounded-lg md:rounded-xl font-mono font-bold text-xs md:text-sm border border-rose-100 flex items-center gap-2">
                        <Clock size={14} />
                        {formatTime(timeLeft)}
                    </div>
                )}

                <button 
                    onClick={(e) => toggleFlag(currentQIndex, e)}
                    className={`p-2 rounded-lg md:rounded-xl border transition-all ${currentQ.isFlagged ? 'bg-rose-100 border-rose-200 text-rose-600' : 'bg-white border-slate-200 text-slate-400'}`}
                >
                    <Flag size={16} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                </button>

                <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-slate-50 rounded-lg md:rounded-xl text-slate-400 border border-slate-100"><LayoutGrid size={16} /></button>
            </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8" ref={scrollRef}>
            <div className="max-w-3xl mx-auto space-y-6 md:space-y-8 pb-20">
                <div className="space-y-4 md:space-y-6">
                    <div className="flex flex-wrap gap-2">
                        <span className="px-2 py-1 bg-slate-100 text-[9px] md:text-[10px] font-black uppercase text-slate-500 rounded-md border border-slate-200">{currentQ.data.category.split(':')[0]}</span>
                        {currentQ.isFlagged && <div className="flex items-center gap-1 text-[9px] font-bold text-rose-600 bg-rose-50 px-2 py-1 rounded border border-rose-100"><Flag size={10} fill="currentColor"/> FLAGGED</div>}
                    </div>

                    <h2 className="text-lg md:text-2xl font-bold text-slate-900 leading-snug" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />

                    {currentQ.data.questionImage && (
                        <div className="rounded-2xl border border-slate-100 bg-slate-50 p-2 overflow-hidden cursor-zoom-in" onClick={() => onImageClick?.(currentQ.data.questionImage!)}>
                            <img src={cleanImageUrl(currentQ.data.questionImage)} className="w-full max-h-[300px] object-contain rounded-xl" alt="Diagram" />
                        </div>
                    )}

                    <div className="grid gap-3">
                        {currentQ.options.map((opt, i) => {
                            const isSelected = currentQ.userAnswer === opt;

                            let containerClass = "border-slate-200 hover:bg-slate-50";
                            let iconClass = "bg-slate-100 text-slate-500";
                            let iconContent = <span className="text-xs">{String.fromCharCode(65 + i)}</span>;

                            if (isExam) {
                                if (isSelected) {
                                    containerClass = "border-slate-900 bg-slate-50 ring-1 ring-slate-900 shadow-md";
                                    iconClass = "bg-slate-900 text-white";
                                }
                            } else {
                                if (showFeedback) {
                                    const isCorrect = opt === currentQ.correctOption;
                                    const isWrong = isSelected && !isCorrect;

                                    if (isCorrect) {
                                        containerClass = "border-emerald-500 bg-emerald-50/50";
                                        iconClass = "bg-emerald-500 text-white";
                                        iconContent = <Check size={14} />;
                                    } else if (isWrong) {
                                        containerClass = "border-rose-500 bg-rose-50/50";
                                        iconClass = "bg-rose-500 text-white";
                                        iconContent = <X size={14} />;
                                    } else {
                                        containerClass = "opacity-50 border-slate-100";
                                    }
                                } else if (isSelected) {
                                    containerClass = "border-slate-900 bg-slate-50";
                                    iconClass = "bg-slate-900 text-white";
                                }
                            }

                            return (
                                <button 
                                    key={i} 
                                    onClick={() => handleOptionSelect(opt)} 
                                    className={`w-full p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 text-left group min-h-[60px] ${containerClass}`}
                                >
                                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold shrink-0 transition-colors ${iconClass}`}>
                                        {iconContent}
                                    </div>
                                    <span className="font-medium text-sm md:text-base text-slate-800" dangerouslySetInnerHTML={{ __html: opt }} />
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* Feedback Section */}
                {showFeedback && (
                    <div className="mt-6 animate-in slide-in-from-bottom-2 duration-700">
                        <div className="rounded-[1.5rem] overflow-hidden border border-slate-200 shadow-xl bg-white relative group">
                            <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>

                            <div className="p-6 md:p-8">
                                <div className="flex items-center justify-between mb-5">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center shadow-sm border border-indigo-100">
                                            <BookOpen size={20} />
                                        </div>
                                        <h4 className="font-black text-sm text-slate-800 uppercase tracking-widest">Deep Dive Analysis</h4>
                                    </div>
                                    {currentQ.userAnswer !== currentQ.correctOption && (
                                        <div className="flex items-center gap-1.5 px-3 py-1.5 bg-rose-50 text-rose-700 rounded-lg text-[10px] font-bold uppercase tracking-wider border border-rose-100">
                                            <AlertTriangle size={12} className="fill-current" /> Auto-Saved
                                        </div>
                                    )}
                                </div>

                                <div className="prose prose-slate max-w-none">
                                    <p className="text-base text-slate-600 leading-8 font-medium" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "Correct identification based on standard anatomical terminology." }} />
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>

        <footer className="h-20 border-t border-slate-100 flex items-center justify-between px-4 md:px-6 shrink-0 bg-white/95 backdrop-blur z-30 fixed bottom-0 left-0 right-0 md:relative">
            <button onClick={() => setCurrentQIndex(c => Math.max(0, c - 1))} disabled={currentQIndex === 0} className="px-4 py-2 rounded-lg font-black text-[10px] uppercase tracking-widest text-slate-400 disabled:opacity-20 flex items-center gap-2 transition-all hover:text-slate-900"><ChevronLeft size={16}/> Back</button>

            {currentQIndex === questions.length - 1 ? (
                <button 
                    onClick={goToSummary} 
                    className="px-6 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-600 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                >
                    Submit Exam <ListChecks size={16} />
                </button>
            ) : (
                <button 
                    onClick={() => setCurrentQIndex(c => c + 1)} 
                    className="px-6 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-600 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                >
                    Next <ChevronRight size={16} />
                </button>
            )}
        </footer>

        {isSidebarOpen && (
            <div className="fixed inset-0 z-50 flex justify-end">
                <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}></div>
                <div className="w-80 h-full bg-white shadow-2xl relative z-10 p-6 flex flex-col animate-in slide-in-from-right duration-300">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-xs font-black uppercase text-slate-900 tracking-widest">Question Map</h3>
                        <button onClick={() => setIsSidebarOpen(false)} className="p-2 bg-slate-50 rounded-lg text-slate-400 hover:text-slate-900"><X size={16} /></button>
                    </div>
                    <div className="flex-1 overflow-y-auto grid grid-cols-5 gap-2 content-start custom-scrollbar p-1">
                        {questions.map((q, i) => (
                            <button 
                                key={i} 
                                onClick={() => { setCurrentQIndex(i); setIsSidebarOpen(false); }} 
                                className={`aspect-square rounded-lg border-2 flex items-center justify-center text-xs font-black transition-all relative ${
                                    currentQIndex === i 
                                        ? 'bg-slate-900 border-slate-900 text-white' 
                                        : q.userAnswer 
                                            ? 'bg-blue-50 border-blue-200 text-blue-600'
                                            : 'bg-slate-50 border-slate-100 text-slate-300'
                                }`}
                            >
                                {i + 1}
                                {q.isFlagged && (
                                    <div className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-rose-500 rounded-full border-2 border-white"></div>
                                )}
                            </button>
                        ))}
                    </div>
                </div>
            </div>
        )}
      </div>
    );
  }

  // --- VIEW: SUMMARY ---
  if (view === 'summary') {
      const answeredCount = questions.filter(q => q.userAnswer).length;
      const flaggedCount = questions.filter(q => q.isFlagged).length;
      const unansweredCount = questions.length - answeredCount;

      return (
          <div className="h-full w-full bg-slate-50 flex flex-col">
              <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
                  <div>
                      <h2 className="text-lg font-black text-slate-900 tracking-tight">Summary</h2>
                  </div>
                  {mode === 'exam' && (
                        <div className="px-3 py-1.5 bg-rose-50 text-rose-600 rounded-lg font-mono font-bold text-xs border border-rose-100 flex items-center gap-2">
                            <Clock size={14} />
                            {formatTime(timeLeft)}
                        </div>
                  )}
              </header>

              <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-12">
                  <div className="max-w-4xl mx-auto space-y-6">
                      <div className="grid grid-cols-3 gap-3 md:gap-4">
                          <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex flex-col items-center">
                              <span className="text-2xl font-black text-blue-600 mb-1">{answeredCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Answered</span>
                          </div>
                          <div className={`bg-white p-4 rounded-xl border shadow-sm flex flex-col items-center ${unansweredCount > 0 ? 'border-rose-100 bg-rose-50' : 'border-slate-100'}`}>
                              <span className={`text-2xl font-black mb-1 ${unansweredCount > 0 ? 'text-rose-600' : 'text-slate-900'}`}>{unansweredCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Unanswered</span>
                          </div>
                          <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex flex-col items-center">
                              <span className="text-2xl font-black text-rose-500 mb-1">{flaggedCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Flagged</span>
                          </div>
                      </div>

                      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                          <div className="grid grid-cols-5 md:grid-cols-10 gap-2">
                              {questions.map((q, i) => (
                                  <button 
                                    key={i}
                                    onClick={() => { setCurrentQIndex(i); setView('playing'); }}
                                    className={`aspect-square rounded-lg border-2 flex items-center justify-center text-xs font-black transition-all relative ${
                                        q.userAnswer 
                                            ? 'bg-blue-50 border-blue-200 text-blue-700' 
                                            : 'bg-slate-50 border-slate-200 text-slate-400'
                                    }`}
                                  >
                                      {i + 1}
                                      {q.isFlagged && <Flag size={10} className="text-rose-500 absolute top-1 right-1" fill="currentColor" />}
                                  </button>
                              ))}
                          </div>
                      </div>
                  </div>
              </div>

              <footer className="p-4 md:p-6 bg-white border-t border-slate-200 shrink-0 flex justify-between items-center">
                  <button onClick={() => setView('playing')} className="px-6 py-3 rounded-xl border-2 border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:border-slate-300">
                      Return
                  </button>
                  <button 
                    onClick={handleFinish} 
                    className="px-8 py-3 bg-slate-900 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-100 flex items-center gap-2"
                  >
                      Finish <CheckCircle2 size={16} />
                  </button>
              </footer>
          </div>
      );
  }

  // --- VIEW: RESULTS ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const pct = questions.length > 0 ? Math.round((score / questions.length) * 100) : 0;
    const mistakesCount = questions.length - score;
    const isPass = pct >= 60;

    return (
        <div className="h-full w-full bg-slate-50 overflow-y-auto custom-scrollbar p-4 flex flex-col items-center">
            <div className="w-full max-w-lg bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col my-auto shrink-0">
                <div className={`p-8 text-center relative overflow-hidden bg-slate-900`}>
                    <div className="relative z-10">
                        <div className={`w-20 h-20 mx-auto rounded-full flex items-center justify-center mb-4 shadow-xl ${isPass ? 'bg-emerald-500 text-white' : 'bg-rose-500 text-white'}`}>
                            {isPass ? <Trophy size={32} fill="currentColor" /> : <RotateCcw size={32} />}
                        </div>
                        <h2 className="text-4xl font-black text-white font-display tracking-tight mb-1">{pct}%</h2>
                        <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em]">{isPass ? 'Passed' : 'Review Needed'}</p>
                    </div>
                    <div className={`absolute top-0 right-0 w-48 h-48 rounded-full blur-[60px] opacity-20 -mr-10 -mt-10 pointer-events-none ${isPass ? 'bg-emerald-400' : 'bg-rose-400'}`}></div>
                </div>

                <div className="p-6 md:p-8 space-y-6 bg-white">
                    <div className="grid grid-cols-2 gap-3">
                        <div className="p-3 rounded-xl bg-slate-50 border border-slate-100 text-center">
                            <span className="block text-xl font-black text-slate-900">{score}</span>
                            <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Correct</span>
                        </div>
                        <div className="p-3 rounded-xl bg-slate-50 border border-slate-100 text-center">
                            <span className="block text-xl font-black text-slate-900">{questions.length}</span>
                            <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Total</span>
                        </div>
                    </div>

                    {mistakesCount > 0 && (
                        <div className="p-4 bg-rose-50 border border-rose-100 rounded-xl flex items-start gap-3">
                            <AlertTriangle className="text-rose-500 shrink-0" size={18} />
                            <div>
                                <h4 className="font-bold text-rose-800 text-sm">Smart Review Updated</h4>
                                <p className="text-xs text-rose-600/80 mt-1">
                                    {mistakesCount} items were added to your Smart Review bank.
                                </p>
                            </div>
                        </div>
                    )}

                    <div className="space-y-3">
                        <button onClick={() => setView('review')} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black uppercase text-xs tracking-[0.15em] shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                            <BarChart3 size={16} /> Review Answers
                        </button>

                        <div className="grid grid-cols-2 gap-3">
                            <button onClick={restartQuiz} className="py-4 bg-white border-2 border-slate-100 rounded-xl font-black uppercase text-[10px] tracking-widest text-slate-500 hover:border-slate-300 hover:text-slate-900 transition-all">
                                Retake
                            </button>
                            <button onClick={() => { if(onExit) onExit(); restartQuiz(); }} className="py-4 bg-white border-2 border-rose-100 rounded-xl font-black uppercase text-[10px] tracking-widest text-rose-500 hover:bg-rose-50 transition-all">
                                Exit
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
      return (
          <div className="h-full flex flex-col bg-slate-50">
              <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 shrink-0 sticky top-0 z-30">
                  <div className="flex items-center gap-3">
                      <button onClick={() => setView('results')} className="p-2 hover:bg-slate-100 rounded-lg transition-colors"><ArrowLeft size={18}/></button>
                      <h3 className="font-black text-xs uppercase tracking-widest">Review</h3>
                  </div>
              </header>
              <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar">
                  <div className="max-w-3xl mx-auto space-y-6">
                      {questions.map((q, idx) => {
                          const isCorrect = q.userAnswer === q.correctOption;
                          return (
                              <div key={idx} className={`bg-white rounded-2xl border-2 overflow-hidden shadow-sm ${isCorrect ? 'border-emerald-100' : 'border-rose-100'}`}>
                                  <div className="p-5 md:p-6 space-y-4">
                                      <div className="flex justify-between items-start">
                                          <span className="text-[9px] font-black uppercase text-slate-400 bg-slate-50 px-2 py-1 rounded">{q.data.category.split(':')[0]}</span>
                                          {isCorrect ? <CheckCircle2 className="text-emerald-500" size={18} /> : <AlertTriangle className="text-rose-500" size={18} />}
                                      </div>

                                      {q.data.questionImage && (
                                          <div className="rounded-xl overflow-hidden border border-slate-100 bg-slate-50 flex items-center justify-center p-2 cursor-zoom-in" onClick={() => onImageClick?.(q.data.questionImage!)}>
                                              <img src={cleanImageUrl(q.data.questionImage)} className="max-h-48 object-contain rounded-lg" alt="Review Diagram" />
                                          </div>
                                      )}

                                      <h4 className="text-base font-bold text-slate-900" dangerouslySetInnerHTML={{ __html: q.data.questionText }} />

                                      <div className="space-y-2">
                                          <div className={`p-3 rounded-lg text-xs font-bold flex items-center justify-between ${isCorrect ? 'bg-emerald-50 text-emerald-900' : 'bg-rose-50 text-rose-900'}`}>
                                              <span>Selected: {q.userAnswer || 'None'}</span>
                                              {!isCorrect && <X size={14} />}
                                          </div>
                                          {!isCorrect && (
                                              <div className="p-3 rounded-lg bg-slate-50 text-slate-900 text-xs font-bold flex items-center justify-between border border-slate-100">
                                                  <span>Correct: {q.correctOption}</span>
                                                  <Check size={14} className="text-emerald-500" />
                                              </div>
                                          )}
                                      </div>

                                      {/* Rationale in Review Mode */}
                                      <div className="p-4 bg-indigo-50/50 rounded-xl border border-indigo-100 mt-2">
                                          <div className="flex items-center gap-2 mb-2 text-indigo-500">
                                              <BookOpen size={14} />
                                              <span className="text-[10px] font-black uppercase tracking-widest">Clinical Reasoning</span>
                                          </div>
                                          <p className="text-xs text-slate-600 leading-relaxed font-medium" dangerouslySetInnerHTML={{ __html: q.data.explanation || "Standard identification." }} />
                                      </div>
                                  </div>
                              </div>
                          );
                      })}
                  </div>
              </div>
              <footer className="p-4 bg-white border-t border-slate-100">
                  <button onClick={restartQuiz} className="w-full py-3.5 bg-slate-900 text-white rounded-xl font-black uppercase text-xs tracking-widest shadow-xl">Back to Setup</button>
              </footer>
          </div>
      );
  }

  return null;
};

export default Quiz;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, CheckCircle2, AlertTriangle, Check, 
  RotateCcw, Trophy, Volume2, BookOpen, 
  BarChart3, ArrowLeft, Flag, ListChecks,
  ImageIcon, Filter, Map as MapIcon, Maximize2
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';
import { cleanImageUrl } from '../utils';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
  isEmbedded?: boolean;
  enableConfiguration?: boolean;
  onExit?: () => void;
  onImageClick?: (url: string) => void;
  mistakes?: string[]; 
  onAddMistake?: (id: string) => void; 
  onRemoveMistake?: (id: string) => void; 
}

const Quiz: React.FC<QuizProps> = ({ 
    data, 
    toggleHeader, 
    isEmbedded = false,
    onExit, 
    onImageClick,
    mistakes = [], 
    onAddMistake, 
    onRemoveMistake 
}) => {
  const [view, setView] = useState<'config' | 'playing' | 'summary' | 'results' | 'review'>('config');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [mode, setMode] = useState<'exam' | 'study' | 'vault' | 'atlas'>('exam');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [questionLimit, setQuestionLimit] = useState(25);

  // Professional Notification State
  const [notification, setNotification] = useState<{show: boolean, type: 'add' | 'remove'}>({ show: false, type: 'add' });

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [onlyDiagrams, setOnlyDiagrams] = useState(false);

  const { speak, isSpeaking, cancel, speakingId } = useSpeech();
  const scrollRef = useRef<HTMLDivElement>(null);

  // --- PERSISTENCE LOGIC ---
  useEffect(() => {
    if (isEmbedded) return; // Don't restore session if embedded

    const savedState = localStorage.getItem('ot_quiz_active_session');
    if (savedState) {
        try {
            const parsed = JSON.parse(savedState);
            // Only resume if we have valid data and we are in config mode
            if (view === 'config' && parsed.questions && parsed.questions.length > 0) {
                setQuestions(parsed.questions);
                setCurrentQIndex(parsed.currentQIndex);
                setTimeLeft(parsed.timeLeft);
                setMode(parsed.mode);
                setView(parsed.view);
                if (toggleHeader) toggleHeader(false);
            }
        } catch (e) {
            console.error("Failed to restore quiz session", e);
            localStorage.removeItem('ot_quiz_active_session');
        }
    }
  }, [isEmbedded]);

  // Save state on every change
  useEffect(() => {
    if (isEmbedded) return; // Don't save embedded sessions

    if (view === 'playing' || view === 'summary') {
        const stateToSave = {
            questions,
            currentQIndex,
            timeLeft,
            mode,
            view
        };
        localStorage.setItem('ot_quiz_active_session', JSON.stringify(stateToSave));
    } else if (view === 'results' || view === 'config') {
        localStorage.removeItem('ot_quiz_active_session');
    }
  }, [questions, currentQIndex, timeLeft, mode, view, isEmbedded]);

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const currentPool = useMemo(() => {
      let pool = data;

      if (mode === 'vault') {
          pool = pool.filter(q => mistakes.includes(q.id));
      } else if (mode === 'atlas') {
          pool = pool.filter(q => q.questionImage || q.answerImage);
      }

      if (selectedCategories.length > 0) {
          pool = pool.filter(q => selectedCategories.includes(q.category));
      }

      if (onlyDiagrams && mode !== 'atlas') {
          pool = pool.filter(q => q.questionImage || q.answerImage);
      }

      return pool;
  }, [mode, mistakes, selectedCategories, data, onlyDiagrams]);

  const currentPoolSize = currentPool.length;

  // Auto-start for embedded mode (Interactive Atlas)
  useEffect(() => {
    if (isEmbedded && view === 'config' && currentPoolSize > 0) {
        setMode('study');
        const prepared = [...currentPool]
            .map(q => ({
                id: q.id, 
                data: q,
                options: (q.options || [q.answerText]).sort(() => Math.random() - 0.5),
                correctOption: q.answerText, 
                userAnswer: null, 
                isFlagged: false
            } as QuizQuestion));

        setQuestions(prepared);
        setCurrentQIndex(0);
        setView('playing');
    }
  }, [isEmbedded, currentPoolSize]); // Only run when pool is ready

  useEffect(() => {
      if (currentPoolSize === 0) {
          setQuestionLimit(0);
      } else if (questionLimit > currentPoolSize) {
          setQuestionLimit(currentPoolSize);
      } else if (questionLimit === 0 && currentPoolSize > 0) {
          setQuestionLimit(Math.min(25, currentPoolSize));
      }
  }, [currentPoolSize, questionLimit]);

  const startSession = () => {
    if (currentPoolSize === 0) {
        if (mode === 'vault') {
             alert("Your Smart Review is empty! Great job mastering the content.");
        } else {
             alert("No questions available with the current filters.");
        }
        return;
    }

    const limit = Math.min(questionLimit, currentPoolSize);
    const prepared = [...currentPool]
        .sort(() => Math.random() - 0.5)
        .slice(0, limit)
        .map(q => ({
            id: q.id, 
            data: q,
            options: (q.options || [q.answerText]).sort(() => Math.random() - 0.5),
            correctOption: q.answerText, 
            userAnswer: null, 
            isFlagged: false
        } as QuizQuestion));

    setQuestions(prepared);
    setCurrentQIndex(0);
    setTimeLeft(prepared.length * 60); 
    setView('playing');
    if (toggleHeader) toggleHeader(false);
  };

  const restartQuiz = () => {
    localStorage.removeItem('ot_quiz_active_session');
    setView('config');
    setQuestions([]);
    if (toggleHeader) toggleHeader(true);
  };

  const toggleFlag = (index: number, e?: React.MouseEvent) => {
      e?.stopPropagation();
      setQuestions(prev => {
          const newQ = [...prev];
          newQ[index].isFlagged = !newQ[index].isFlagged;
          return newQ;
      });
  };

  const goToSummary = () => {
      setView('summary');
  };

  // --- IMMEDIATE MISTAKE SYSTEM LOGIC ---
  const handleOptionSelect = (option: string) => {
      const currentQ = questions[currentQIndex];

      // If already answered in Study/Vault mode, ignore click
      if ((mode === 'study' || mode === 'vault' || mode === 'atlas') && currentQ.userAnswer) return;

      const isCorrect = option === currentQ.correctOption;

      // 1. Update Local State
      setQuestions(prev => { 
          const c = [...prev]; 
          c[currentQIndex].userAnswer = option; 
          return c; 
      });

      // 2. Immediate Smart Review Update
      if (!isCorrect) {
          // If wrong, add to mistakes immediately
          onAddMistake?.(currentQ.id);

          // Show "Added" Notification
          setNotification({ show: true, type: 'add' });
          setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 2000);
      } 
      else if (isCorrect && mode === 'vault') {
          // If correct AND we are in Review Mode, remove it
          onRemoveMistake?.(currentQ.id);

          // Show "Removed/Mastered" Notification
          setNotification({ show: true, type: 'remove' });
          setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 2000);
      }
  };

  const handleFinish = () => {
    cancel();
    localStorage.removeItem('ot_quiz_active_session');

    // AUTOMATICALLY ADD UNANSWERED OR WRONG QUESTIONS TO MISTAKES
    questions.forEach(q => {
        const isWrongOrSkipped = q.userAnswer !== q.correctOption;
        if (isWrongOrSkipped) {
            onAddMistake?.(q.id);
        }
    });

    setView('results');
  };

  useEffect(() => {
    let timer: any;
    if ((view === 'playing' || view === 'summary') && mode === 'exam' && timeLeft > 0) {
      timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && (view === 'playing' || view === 'summary') && mode === 'exam') {
        handleFinish();
    }
    return () => clearInterval(timer);
  }, [timeLeft, view, mode]);

  // --- FILTER OPTIONS FOR MODAL ---
  const quizFilterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Questions',
        icon: ImageIcon,
        isActive: onlyDiagrams,
        onClick: () => setOnlyDiagrams(!onlyDiagrams),
        colorTheme: 'rose'
    }
  ];

  // --- VIEW: CONFIGURATION ---
  if (view === 'config') {
    const filtersActive = selectedCategories.length > 0 || (onlyDiagrams && mode !== 'atlas');

    return (
      <div className="h-full w-full flex items-center justify-center p-4 bg-slate-50/50 pb-32 md:pb-4">
          <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col max-h-[75vh] md:max-h-[90vh]">
            <div className="bg-slate-900 p-6 md:p-8 relative overflow-hidden shrink-0">
                <div className="relative z-10">
                    <h2 className="text-2xl md:text-3xl font-black text-white font-display tracking-tight">Exam Configuration</h2>
                    <p className="text-rose-500 text-xs font-bold uppercase tracking-[0.2em] mt-1">Anatomy and Physiology OT</p>
                </div>
                <div className="absolute right-0 top-0 w-64 h-64 bg-rose-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            </div>

            <div className="flex-1 p-6 md:p-8 space-y-4 overflow-y-auto custom-scrollbar">
                <div className="grid grid-cols-2 gap-3">
                    <button 
                        onClick={() => setMode('exam')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'exam' ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'exam' ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Clock size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'exam' ? 'text-rose-900' : 'text-slate-900'}`}>Exam</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Strict Timing</p>
                    </button>

                    <button 
                        onClick={() => setMode('study')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'study' ? 'border-indigo-200 bg-indigo-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'study' ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Zap size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'study' ? 'text-indigo-900' : 'text-slate-900'}`}>Study</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Instant Feedback</p>
                    </button>

                    <button 
                        onClick={() => setMode('vault')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'vault' ? 'border-amber-200 bg-amber-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'vault' ? 'bg-amber-100 text-amber-600' : 'bg-slate-50 text-slate-400'}`}>
                            <AlertTriangle size={18} />
                        </div>
                        <div className="flex justify-between items-center">
                            <h3 className={`font-bold text-sm ${mode === 'vault' ? 'text-amber-900' : 'text-slate-900'}`}>Smart Review</h3>
                            {mistakes.length > 0 && <span className="bg-amber-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-md">{mistakes.length}</span>}
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Fix Mistakes</p>
                    </button>

                    <button 
                        onClick={() => setMode('atlas')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'atlas' ? 'border-teal-200 bg-teal-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'atlas' ? 'bg-teal-100 text-teal-600' : 'bg-slate-50 text-slate-400'}`}>
                            <MapIcon size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'atlas' ? 'text-teal-900' : 'text-slate-900'}`}>Atlas Mode</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Visual Lab</p>
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <button 
                        onClick={() => setIsFilterOpen(true)}
                        className={`p-4 rounded-2xl border-2 text-left transition-all flex items-center justify-between group ${filtersActive ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-slate-50 hover:bg-white hover:border-slate-200'}`}
                    >
                        <div className="flex items-center gap-3 overflow-hidden">
                            <div className={`p-2 rounded-lg ${filtersActive ? 'bg-rose-100 text-rose-600' : 'bg-white border border-slate-200 text-slate-400 group-hover:text-rose-500'}`}>
                                <Filter size={16}/>
                            </div>
                            <div className="flex flex-col text-left min-w-0">
                                <span className={`text-[10px] font-black uppercase tracking-wider ${filtersActive ? 'text-rose-400' : 'text-slate-400'}`}>Filters</span>
                                <span className={`font-bold text-xs truncate ${filtersActive ? 'text-rose-900' : 'text-slate-700'}`}>
                                    {selectedCategories.length > 0 ? `${selectedCategories.length} Chapters` : 'Default Pool'}
                                </span>
                            </div>
                        </div>
                        <ChevronRight size={16} className={`${filtersActive ? 'text-rose-400' : 'text-slate-400'} group-hover:translate-x-1 transition-transform shrink-0`} />
                    </button>

                    <div className="p-4 rounded-2xl border border-slate-200 bg-slate-50 flex flex-col justify-center gap-2">
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Question Limit</span>
                            <span className="font-bold text-xs text-slate-900 bg-white px-2 py-1 rounded border border-slate-200">{questionLimit}</span>
                        </div>
                        <input 
                            type="range" 
                            min={Math.min(1, currentPoolSize)}
                            max={currentPoolSize} 
                            step="1" 
                            value={questionLimit || 0}
                            onChange={(e) => setQuestionLimit(parseInt(e.target.value))}
                            disabled={currentPoolSize === 0}
                            className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900 hover:accent-rose-600 transition-all"
                        />
                    </div>
                </div>
            </div>

            <div className="p-4 md:p-6 border-t border-slate-100 bg-white shrink-0">
                <button 
                    onClick={startSession}
                    disabled={currentPoolSize === 0}
                    className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-rose-600 transition-all shadow-xl hover:shadow-rose-200 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                    Start Exam <ChevronRight size={16} />
                </button>
            </div>
          </div>

          <FilterModal
            isOpen={isFilterOpen}
            onClose={() => setIsFilterOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => { setSelectedCategories([]); setOnlyDiagrams(false); }}
            mainOptions={quizFilterOptions}
            title="Exam Settings"
          />
      </div>
    );
  }

  // --- VIEW: PLAYING ---
  const currentQ = questions[currentQIndex];
  if (view === 'playing' && currentQ) {
    const isExam = mode === 'exam';
    const isAtlasMode = mode === 'atlas';
    const isStudy = mode === 'study' || mode === 'vault' || isAtlasMode; 
    const showFeedback = isStudy && currentQ.userAnswer; 

    return (
      <div className="h-full flex flex-col bg-white relative">

        {/* --- PROFESSIONAL NOTIFICATION --- */}
        {notification.show && (
            <div className="absolute top-20 left-0 right-0 flex justify-center z-50 pointer-events-none animate-in fade-in slide-in-from-top-4">
                <div className={`px-6 py-3 rounded-full shadow-2xl border-2 flex items-center gap-3 font-bold text-xs uppercase tracking-widest ${
                    notification.type === 'add' 
                    ? 'bg-rose-500 text-white border-white' 
                    : 'bg-emerald-500 text-white border-white'
                }`}>
                    {notification.type === 'add' ? (
                        <>
                            <AlertTriangle size={16} className="fill-current text-white" />
                            <span>Added to Smart Review</span>
                        </>
                    ) : (
                        <>
                            <CheckCircle2 size={16} className="fill-current text-white" />
                            <span>Mastered & Removed</span>
                        </>
                    )}
                </div>
            </div>
        )}

        <header className="h-14 md:h-16 glass border-b border-slate-100 flex items-center justify-between px-4 md:px-6 shrink-0 z-30">
            <div className="flex items-center gap-3 md:gap-4">
                <div className="w-8 h-8 md:w-10 md:h-10 bg-slate-900 text-white rounded-lg md:rounded-xl flex items-center justify-center font-black text-xs">
                    {currentQIndex + 1}
                </div>
                <div>
                    <h1 className="text-[10px] font-black uppercase text-slate-400 tracking-widest leading-none hidden md:block">
                        {isExam ? 'Assessment' : 'Study'}
                    </h1>
                    <p className="text-xs font-bold text-slate-900 truncate max-w-[120px] md:max-w-none">Anatomy and Physiology OT</p>
                </div>
            </div>
            <div className="flex items-center gap-2 md:gap-3">

                <button 
                    onClick={goToSummary}
                    className="flex items-center gap-1.5 px-3 py-1.5 bg-white border border-slate-200 text-slate-600 rounded-lg md:rounded-xl font-bold text-[10px] md:text-xs uppercase tracking-wider hover:bg-slate-50 hover:text-slate-900 transition-all shadow-sm"
                    title="Finish Exam Immediately"
                >
                    <ListChecks size={16} className="text-emerald-500" />
                    <span className="hidden sm:inline">Submit</span>
                </button>

                {isExam && (
                    <div className="px-3 py-1.5 md:px-4 md:py-2 bg-rose-50 text-rose-600 rounded-lg md:rounded-xl font-mono font-bold text-xs md:text-sm border border-rose-100 flex items-center gap-2">
                        <Clock size={14} />
                        {formatTime(timeLeft)}
                    </div>
                )}

                <button 
                    onClick={(e) => toggleFlag(currentQIndex, e)}
                    className={`p-2 rounded-lg md:rounded-xl border transition-all ${currentQ.isFlagged ? 'bg-rose-100 border-rose-200 text-rose-600' : 'bg-white border-slate-200 text-slate-400'}`}
                >
                    <Flag size={16} fill={currentQ.isFlagged ? "currentColor" : "none"} />
                </button>

                <button onClick={() => setIsSidebarOpen(true)} className="p-2 bg-slate-50 rounded-lg md:rounded-xl text-slate-400 border border-slate-100"><LayoutGrid size={16} /></button>
            </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-8" ref={scrollRef}>
            <div className="max-w-3xl mx-auto space-y-6 md:space-y-8 pb-20">
                <div className="space-y-4 md:space-y-6">
                    <div className="flex flex-wrap gap-2">
                        <span className="px-2 py-1 bg-slate-100 text-[9px] md:text-[10px] font-black uppercase text-slate-500 rounded-md border border-slate-200">{currentQ.data.category.split(':')[0]}</span>
                        {currentQ.isFlagged && <div className="flex items-center gap-1 text-[9px] font-bold text-rose-600 bg-rose-50 px-2 py-1 rounded border border-rose-100"><Flag size={10} fill="currentColor"/> FLAGGED</div>}
                    </div>

                    <h2 className="text-lg md:text-2xl font-bold text-slate-900 leading-snug" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText }} />

                    {currentQ.data.questionImage && (
                        <div 
                            className={`rounded-2xl border overflow-hidden cursor-zoom-in relative group transition-all ${
                                isAtlasMode 
                                    ? 'bg-slate-50 border-slate-200 p-4 md:p-8 flex items-center justify-center min-h-[40vh] shadow-inner' 
                                    : 'bg-slate-50 border-slate-100 p-2'
                            }`} 
                            onClick={() => onImageClick?.(currentQ.data.questionImage!)}
                        >
                            <img 
                                src={cleanImageUrl(currentQ.data.questionImage)} 
                                className={`w-full object-contain rounded-xl transition-all ${
                                    isAtlasMode ? 'max-h-[50vh] md:max-h-[60vh] mix-blend-multiply' : 'max-h-[300px]'
                                }`} 
                                alt="Diagram" 
                            />
                            {isAtlasMode && (
                                <div className="absolute top-4 right-4 p-2 bg-white/90 backdrop-blur rounded-xl opacity-0 group-hover:opacity-100 transition-opacity shadow-sm border border-slate-200 text-slate-500">
                                    <Maximize2 size={18} />
                                </div>
                            )}
                        </div>
                    )}

                    <div className="grid gap-3">
                        {currentQ.options.map((opt, i) => {
                            const isSelected = currentQ.userAnswer === opt;

                            let containerClass = "border-slate-200 hover:bg-slate-50";
                            let iconClass = "bg-slate-100 text-slate-500";
                            let iconContent = <span className="text-xs">{String.fromCharCode(65 + i)}</span>;

                            if (isExam) {
                                if (isSelected) {
                                    containerClass = "border-slate-900 bg-slate-50 ring-1 ring-slate-900 shadow-md";
                                    iconClass = "bg-slate-900 text-white";
                                }
                            } else {
                                if (showFeedback) {
                                    const isCorrect = opt === currentQ.correctOption;
                                    const isWrong = isSelected && !isCorrect;

                                    if (isCorrect) {
                                        containerClass = "border-emerald-500 bg-emerald-50/50";
                                        iconClass = "bg-emerald-500 text-white";
                                        iconContent = <Check size={14} />;
                                    } else if (isWrong) {
                                        containerClass = "border-rose-500 bg-rose-50/50";
                                        iconClass = "bg-rose-500 text-white";
                                        iconContent = <X size={14} />;
                                    } else {
                                        containerClass = "opacity-50 border-slate-100";
                                    }
                                } else if (isSelected) {
                                    containerClass = "border-slate-900 bg-slate-50";
                                    iconClass = "bg-slate-900 text-white";
                                }
                            }

                            return (
                                <button 
                                    key={i} 
                                    onClick={() => handleOptionSelect(opt)} 
                                    className={`w-full p-4 md:p-5 rounded-xl border-2 transition-all flex items-center gap-4 text-left group min-h-[60px] ${containerClass}`}
                                >
                                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold shrink-0 transition-colors ${iconClass}`}>
                                        {iconContent}
                                    </div>
                                    <span className="font-medium text-sm md:text-base text-slate-800" dangerouslySetInnerHTML={{ __html: opt }} />
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* Feedback Section */}
                {showFeedback && (
                    <div className="mt-6 animate-in slide-in-from-bottom-2 duration-700">
                        <div className="rounded-[1.5rem] overflow-hidden border border-slate-200 shadow-xl bg-white relative group">
                            <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>

                            <div className="p-6 md:p-8">
                                <div className="flex items-center justify-between mb-5">
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center shadow-sm border border-indigo-100">
                                            <BookOpen size={20} />
                                        </div>
                                        <h4 className="font-black text-sm text-slate-800 uppercase tracking-widest">Deep Dive Analysis</h4>
                                    </div>
                                    {currentQ.userAnswer !== currentQ.correctOption && (
                                        <div className="flex items-center gap-1.5 px-3 py-1.5 bg-rose-50 text-rose-700 rounded-lg text-[10px] font-bold uppercase tracking-wider border border-rose-100">
                                            <AlertTriangle size={12} className="fill-current" /> Auto-Saved
                                        </div>
                                    )}
                                </div>

                                <div className="prose prose-slate max-w-none">
                                    <p className="text-base text-slate-600 leading-8 font-medium" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "Correct identification based on standard anatomical terminology." }} />
                                </div>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>

        <footer className="h-20 border-t border-slate-100 flex items-center justify-between px-4 md:px-6 shrink-0 bg-white/95 backdrop-blur z-30 fixed bottom-0 left-0 right-0 md:relative">
            <button onClick={() => setCurrentQIndex(c => Math.max(0, c - 1))} disabled={currentQIndex === 0} className="px-4 py-2 rounded-lg font-black text-[10px] uppercase tracking-widest text-slate-400 disabled:opacity-20 flex items-center gap-2 transition-all hover:text-slate-900"><ChevronLeft size={16}/> Back</button>

            {currentQIndex === questions.length - 1 ? (
                <button 
                    onClick={goToSummary} 
                    className="px-6 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-600 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                >
                    Submit Exam <ListChecks size={16} />
                </button>
            ) : (
                <button 
                    onClick={() => setCurrentQIndex(c => c + 1)} 
                    className="px-6 py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-rose-600 transition-all shadow-lg active:scale-95 flex items-center gap-2"
                >
                    Next <ChevronRight size={16} />
                </button>
            )}
        </footer>

        {isSidebarOpen && (
            <div className="fixed inset-0 z-50 flex justify-end">
                <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-sm" onClick={() => setIsSidebarOpen(false)}></div>
                <div className="w-80 h-full bg-white shadow-2xl relative z-10 p-6 flex flex-col animate-in slide-in-from-right duration-300">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-xs font-black uppercase text-slate-900 tracking-widest">Question Map</h3>
                        <button onClick={() => setIsSidebarOpen(false)} className="p-2 bg-slate-50 rounded-lg text-slate-400 hover:text-slate-900"><X size={16} /></button>
                    </div>
                    <div className="flex-1 overflow-y-auto grid grid-cols-5 gap-2 content-start custom-scrollbar p-1">
                        {questions.map((q, i) => (
                            <button 
                                key={i} 
                                onClick={() => { setCurrentQIndex(i); setIsSidebarOpen(false); }} 
                                className={`aspect-square rounded-lg border-2 flex items-center justify-center text-xs font-black transition-all relative ${
                                    currentQIndex === i 
                                        ? 'bg-slate-900 border-slate-900 text-white' 
                                        : q.userAnswer 
                                            ? 'bg-blue-50 border-blue-200 text-blue-600'
                                            : 'bg-slate-50 border-slate-100 text-slate-300'
                                }`}
                            >
                                {i + 1}
                                {q.isFlagged && (
                                    <div className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-rose-500 rounded-full border-2 border-white"></div>
                                )}
                            </button>
                        ))}
                    </div>
                </div>
            </div>
        )}
      </div>
    );
  }

  // --- VIEW: SUMMARY ---
  if (view === 'summary') {
      const answeredCount = questions.filter(q => q.userAnswer).length;
      const flaggedCount = questions.filter(q => q.isFlagged).length;
      const unansweredCount = questions.length - answeredCount;

      return (
          <div className="h-full w-full bg-slate-50 flex flex-col">
              <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-6 shrink-0">
                  <div>
                      <h2 className="text-lg font-black text-slate-900 tracking-tight">Summary</h2>
                  </div>
                  {mode === 'exam' && (
                        <div className="px-3 py-1.5 bg-rose-50 text-rose-600 rounded-lg font-mono font-bold text-xs border border-rose-100 flex items-center gap-2">
                            <Clock size={14} />
                            {formatTime(timeLeft)}
                        </div>
                  )}
              </header>

              <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-12">
                  <div className="max-w-4xl mx-auto space-y-6">
                      <div className="grid grid-cols-3 gap-3 md:gap-4">
                          <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex flex-col items-center">
                              <span className="text-2xl font-black text-blue-600 mb-1">{answeredCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Answered</span>
                          </div>
                          <div className={`bg-white p-4 rounded-xl border shadow-sm flex flex-col items-center ${unansweredCount > 0 ? 'border-rose-100 bg-rose-50' : 'border-slate-100'}`}>
                              <span className={`text-2xl font-black mb-1 ${unansweredCount > 0 ? 'text-rose-600' : 'text-slate-900'}`}>{unansweredCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Unanswered</span>
                          </div>
                          <div className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm flex flex-col items-center">
                              <span className="text-2xl font-black text-rose-500 mb-1">{flaggedCount}</span>
                              <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Flagged</span>
                          </div>
                      </div>

                      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                          <div className="grid grid-cols-5 md:grid-cols-10 gap-2">
                              {questions.map((q, i) => (
                                  <button 
                                    key={i}
                                    onClick={() => { setCurrentQIndex(i); setView('playing'); }}
                                    className={`aspect-square rounded-lg border-2 flex items-center justify-center text-xs font-black transition-all relative ${
                                        q.userAnswer 
                                            ? 'bg-blue-50 border-blue-200 text-blue-700' 
                                            : 'bg-slate-50 border-slate-200 text-slate-400'
                                    }`}
                                  >
                                      {i + 1}
                                      {q.isFlagged && <Flag size={10} className="text-rose-500 absolute top-1 right-1" fill="currentColor" />}
                                  </button>
                              ))}
                          </div>
                      </div>
                  </div>
              </div>

              <footer className="p-4 md:p-6 bg-white border-t border-slate-200 shrink-0 flex justify-between items-center">
                  <button onClick={() => setView('playing')} className="px-6 py-3 rounded-xl border-2 border-slate-200 text-slate-600 font-bold text-xs uppercase tracking-widest hover:border-slate-300">
                      Return
                  </button>
                  <button 
                    onClick={handleFinish} 
                    className="px-8 py-3 bg-slate-900 text-white rounded-xl font-black text-xs uppercase tracking-widest hover:bg-emerald-600 transition-all shadow-xl shadow-emerald-100 flex items-center gap-2"
                  >
                      Finish <CheckCircle2 size={16} />
                  </button>
              </footer>
          </div>
      );
  }

  // --- VIEW: RESULTS ---
  if (view === 'results') {
    const score = questions.filter(q => q.userAnswer === q.correctOption).length;
    const pct = questions.length > 0 ? Math.round((score / questions.length) * 100) : 0;
    const mistakesCount = questions.length - score;
    const isPass = pct >= 60;

    return (
        <div className="h-full w-full bg-slate-50 overflow-y-auto custom-scrollbar p-4 flex flex-col items-center">
            <div className="w-full max-w-lg bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col my-auto shrink-0">
                <div className={`p-8 text-center relative overflow-hidden bg-slate-900`}>
                    <div className="relative z-10">
                        <div className={`w-20 h-20 mx-auto rounded-full flex items-center justify-center mb-4 shadow-xl ${isPass ? 'bg-emerald-500 text-white' : 'bg-rose-500 text-white'}`}>
                            {isPass ? <Trophy size={32} fill="currentColor" /> : <RotateCcw size={32} />}
                        </div>
                        <h2 className="text-4xl font-black text-white font-display tracking-tight mb-1">{pct}%</h2>
                        <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em]">{isPass ? 'Passed' : 'Review Needed'}</p>
                    </div>
                    <div className={`absolute top-0 right-0 w-48 h-48 rounded-full blur-[60px] opacity-20 -mr-10 -mt-10 pointer-events-none ${isPass ? 'bg-emerald-400' : 'bg-rose-400'}`}></div>
                </div>

                <div className="p-6 md:p-8 space-y-6 bg-white">
                    <div className="grid grid-cols-2 gap-3">
                        <div className="p-3 rounded-xl bg-slate-50 border border-slate-100 text-center">
                            <span className="block text-xl font-black text-slate-900">{score}</span>
                            <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Correct</span>
                        </div>
                        <div className="p-3 rounded-xl bg-slate-50 border border-slate-100 text-center">
                            <span className="block text-xl font-black text-slate-900">{questions.length}</span>
                            <span className="text-[10px] font-bold uppercase text-slate-400 tracking-widest">Total</span>
                        </div>
                    </div>

                    {mistakesCount > 0 && (
                        <div className="p-4 bg-rose-50 border border-rose-100 rounded-xl flex items-start gap-3">
                            <AlertTriangle className="text-rose-500 shrink-0" size={18} />
                            <div>
                                <h4 className="font-bold text-rose-800 text-sm">Smart Review Updated</h4>
                                <p className="text-xs text-rose-600/80 mt-1">
                                    {mistakesCount} items were added to your Smart Review bank.
                                </p>
                            </div>
                        </div>
                    )}

                    <div className="space-y-3">
                        <button onClick={() => setView('review')} className="w-full py-4 bg-slate-900 text-white rounded-xl font-black uppercase text-xs tracking-[0.15em] shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                            <BarChart3 size={16} /> Review Answers
                        </button>

                        <div className="grid grid-cols-2 gap-3">
                            <button onClick={restartQuiz} className="py-4 bg-white border-2 border-slate-100 rounded-xl font-black uppercase text-[10px] tracking-widest text-slate-500 hover:border-slate-300 hover:text-slate-900 transition-all">
                                Retake
                            </button>
                            <button onClick={() => { if(onExit) onExit(); restartQuiz(); }} className="py-4 bg-white border-2 border-rose-100 rounded-xl font-black uppercase text-[10px] tracking-widest text-rose-500 hover:bg-rose-50 transition-all">
                                Exit
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
  }

  // --- VIEW: REVIEW ---
  if (view === 'review') {
      return (
          <div className="h-full flex flex-col bg-slate-50">
              <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-4 shrink-0 sticky top-0 z-30">
                  <div className="flex items-center gap-3">
                      <button onClick={() => setView('results')} className="p-2 hover:bg-slate-100 rounded-lg transition-colors"><ArrowLeft size={18}/></button>
                      <h3 className="font-black text-xs uppercase tracking-widest">Review</h3>
                  </div>
              </header>
              <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar">
                  <div className="max-w-3xl mx-auto space-y-6">
                      {questions.map((q, idx) => {
                          const isCorrect = q.userAnswer === q.correctOption;
                          return (
                              <div key={idx} className={`bg-white rounded-2xl border-2 overflow-hidden shadow-sm ${isCorrect ? 'border-emerald-100' : 'border-rose-100'}`}>
                                  <div className="p-5 md:p-6 space-y-4">
                                      <div className="flex justify-between items-start">
                                          <span className="text-[9px] font-black uppercase text-slate-400 bg-slate-50 px-2 py-1 rounded">{q.data.category.split(':')[0]}</span>
                                          {isCorrect ? <CheckCircle2 className="text-emerald-500" size={18} /> : <AlertTriangle className="text-rose-500" size={18} />}
                                      </div>

                                      {q.data.questionImage && (
                                          <div className="rounded-xl overflow-hidden border border-slate-100 bg-slate-50 flex items-center justify-center p-2 cursor-zoom-in" onClick={() => onImageClick?.(q.data.questionImage!)}>
                                              <img src={cleanImageUrl(q.data.questionImage)} className="max-h-48 object-contain rounded-lg" alt="Review Diagram" />
                                          </div>
                                      )}

                                      <h4 className="text-base font-bold text-slate-900" dangerouslySetInnerHTML={{ __html: q.data.questionText }} />

                                      <div className="space-y-2">
                                          <div className={`p-3 rounded-lg text-xs font-bold flex items-center justify-between ${isCorrect ? 'bg-emerald-50 text-emerald-900' : 'bg-rose-50 text-rose-900'}`}>
                                              <span>Selected: {q.userAnswer || 'None'}</span>
                                              {!isCorrect && <X size={14} />}
                                          </div>
                                          {!isCorrect && (
                                              <div className="p-3 rounded-lg bg-slate-50 text-slate-900 text-xs font-bold flex items-center justify-between border border-slate-100">
                                                  <span>Correct: {q.correctOption}</span>
                                                  <Check size={14} className="text-emerald-500" />
                                              </div>
                                          )}
                                      </div>

                                      {/* Rationale in Review Mode */}
                                      <div className="p-4 bg-indigo-50/50 rounded-xl border border-indigo-100 mt-2">
                                          <div className="flex items-center gap-2 mb-2 text-indigo-500">
                                              <BookOpen size={14} />
                                              <span className="text-[10px] font-black uppercase tracking-widest">Clinical Reasoning</span>
                                          </div>
                                          <p className="text-xs text-slate-600 leading-relaxed font-medium" dangerouslySetInnerHTML={{ __html: q.data.explanation || "Standard identification." }} />
                                      </div>
                                  </div>
                              </div>
                          );
                      })}
                  </div>
              </div>
              <footer className="p-4 bg-white border-t border-slate-100">
                  <button onClick={restartQuiz} className="w-full py-3.5 bg-slate-900 text-white rounded-xl font-black uppercase text-xs tracking-widest shadow-xl">Back to Setup</button>
              </footer>
          </div>
      );
  }

  return null;
};

export default Quiz;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Question, QuizQuestion } from '../types';
import { 
  X, Clock, ChevronLeft, ChevronRight, 
  LayoutGrid, Zap, CheckCircle2, AlertTriangle, Check, 
  RotateCcw, Trophy, Volume2, BookOpen, 
  BarChart3, ArrowLeft, Flag, ListChecks,
  ImageIcon, Filter, Map as MapIcon, Maximize2, Scan, Eye
} from 'lucide-react';
import { useSpeech } from '../hooks/useSpeech';
import FilterModal, { FilterOption } from './FilterModal';
import { cleanImageUrl } from '../utils';

const formatTime = (seconds: number) => {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, '0')}`;
};

interface QuizProps {
  data: Question[];
  toggleHeader?: (visible: boolean) => void;
  isEmbedded?: boolean;
  enableConfiguration?: boolean;
  onExit?: () => void;
  onImageClick?: (url: string) => void;
  mistakes?: string[]; 
  onAddMistake?: (id: string) => void; 
  onRemoveMistake?: (id: string) => void; 
}

const Quiz: React.FC<QuizProps> = ({ 
    data, 
    toggleHeader, 
    isEmbedded = false,
    onExit, 
    onImageClick,
    mistakes = [], 
    onAddMistake, 
    onRemoveMistake 
}) => {
  const [view, setView] = useState<'config' | 'playing' | 'summary' | 'results' | 'review'>('config');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentQIndex, setCurrentQIndex] = useState(0);
  const [timeLeft, setTimeLeft] = useState(0);
  const [mode, setMode] = useState<'exam' | 'study' | 'vault' | 'atlas'>('exam');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [questionLimit, setQuestionLimit] = useState(25);

  // Professional Notification State
  const [notification, setNotification] = useState<{show: boolean, type: 'add' | 'remove'}>({ show: false, type: 'add' });

  // Filter States
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [onlyDiagrams, setOnlyDiagrams] = useState(false);

  const { speak, isSpeaking, cancel, speakingId } = useSpeech();
  const scrollRef = useRef<HTMLDivElement>(null);

  // --- PERSISTENCE LOGIC ---
  useEffect(() => {
    if (isEmbedded) return; // Don't restore session if embedded

    const savedState = localStorage.getItem('ot_quiz_active_session');
    if (savedState) {
        try {
            const parsed = JSON.parse(savedState);
            // Only resume if we have valid data and we are in config mode
            if (view === 'config' && parsed.questions && parsed.questions.length > 0) {
                setQuestions(parsed.questions);
                setCurrentQIndex(parsed.currentQIndex);
                setTimeLeft(parsed.timeLeft);
                setMode(parsed.mode);
                setView(parsed.view);
                if (toggleHeader) toggleHeader(false);
            }
        } catch (e) {
            console.error("Failed to restore quiz session", e);
            localStorage.removeItem('ot_quiz_active_session');
        }
    }
  }, [isEmbedded]);

  // Save state on every change
  useEffect(() => {
    if (isEmbedded) return; // Don't save embedded sessions

    if (view === 'playing' || view === 'summary') {
        const stateToSave = {
            questions,
            currentQIndex,
            timeLeft,
            mode,
            view
        };
        localStorage.setItem('ot_quiz_active_session', JSON.stringify(stateToSave));
    } else if (view === 'results' || view === 'config') {
        localStorage.removeItem('ot_quiz_active_session');
    }
  }, [questions, currentQIndex, timeLeft, mode, view, isEmbedded]);

  const categories = useMemo(() => {
    const cats = new Set(data.map(q => q.category));
    return Array.from(cats).sort((a: string, b: string) => 
      a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' })
    );
  }, [data]);

  const currentPool = useMemo(() => {
      let pool = data;

      if (mode === 'vault') {
          pool = pool.filter(q => mistakes.includes(q.id));
      } else if (mode === 'atlas') {
          pool = pool.filter(q => q.questionImage || q.answerImage);
      }

      if (selectedCategories.length > 0) {
          pool = pool.filter(q => selectedCategories.includes(q.category));
      }

      if (onlyDiagrams && mode !== 'atlas') {
          pool = pool.filter(q => q.questionImage || q.answerImage);
      }

      return pool;
  }, [mode, mistakes, selectedCategories, data, onlyDiagrams]);

  const currentPoolSize = currentPool.length;

  // Auto-start for embedded mode (Interactive Atlas)
  useEffect(() => {
    if (isEmbedded && view === 'config' && currentPoolSize > 0) {
        setMode('study'); // Or 'atlas' if preferred, but study logic works
        const prepared = [...currentPool]
            .map(q => ({
                id: q.id, 
                data: q,
                options: (q.options || [q.answerText]).sort(() => Math.random() - 0.5),
                correctOption: q.answerText, 
                userAnswer: null, 
                isFlagged: false
            } as QuizQuestion));

        setQuestions(prepared);
        setCurrentQIndex(0);
        setView('playing');
    }
  }, [isEmbedded, currentPoolSize]); 

  useEffect(() => {
      if (currentPoolSize === 0) {
          setQuestionLimit(0);
      } else if (questionLimit > currentPoolSize) {
          setQuestionLimit(currentPoolSize);
      } else if (questionLimit === 0 && currentPoolSize > 0) {
          setQuestionLimit(Math.min(25, currentPoolSize));
      }
  }, [currentPoolSize, questionLimit]);

  const startSession = () => {
    if (currentPoolSize === 0) {
        if (mode === 'vault') {
             alert("Your Smart Review is empty! Great job mastering the content.");
        } else {
             alert("No questions available with the current filters.");
        }
        return;
    }

    const limit = Math.min(questionLimit, currentPoolSize);
    const prepared = [...currentPool]
        .sort(() => Math.random() - 0.5)
        .slice(0, limit)
        .map(q => ({
            id: q.id, 
            data: q,
            options: (q.options || [q.answerText]).sort(() => Math.random() - 0.5),
            correctOption: q.answerText, 
            userAnswer: null, 
            isFlagged: false
        } as QuizQuestion));

    setQuestions(prepared);
    setCurrentQIndex(0);
    setTimeLeft(prepared.length * 60); 
    setView('playing');
    if (toggleHeader) toggleHeader(false);
  };

  const restartQuiz = () => {
    localStorage.removeItem('ot_quiz_active_session');
    setView('config');
    setQuestions([]);
    if (toggleHeader) toggleHeader(true);
  };

  const toggleFlag = (index: number, e?: React.MouseEvent) => {
      e?.stopPropagation();
      setQuestions(prev => {
          const newQ = [...prev];
          newQ[index].isFlagged = !newQ[index].isFlagged;
          return newQ;
      });
  };

  const goToSummary = () => {
      setView('summary');
  };

  const handleOptionSelect = (option: string) => {
      const currentQ = questions[currentQIndex];
      if ((mode === 'study' || mode === 'vault' || mode === 'atlas') && currentQ.userAnswer) return;

      const isCorrect = option === currentQ.correctOption;
      setQuestions(prev => { 
          const c = [...prev]; 
          c[currentQIndex].userAnswer = option; 
          return c; 
      });

      if (!isCorrect) {
          onAddMistake?.(currentQ.id);
          setNotification({ show: true, type: 'add' });
          setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 2000);
      } 
      else if (isCorrect && mode === 'vault') {
          onRemoveMistake?.(currentQ.id);
          setNotification({ show: true, type: 'remove' });
          setTimeout(() => setNotification(prev => ({ ...prev, show: false })), 2000);
      }
  };

  const handleFinish = () => {
    cancel();
    localStorage.removeItem('ot_quiz_active_session');
    questions.forEach(q => {
        const isWrongOrSkipped = q.userAnswer !== q.correctOption;
        if (isWrongOrSkipped) {
            onAddMistake?.(q.id);
        }
    });
    setView('results');
  };

  useEffect(() => {
    let timer: any;
    if ((view === 'playing' || view === 'summary') && mode === 'exam' && timeLeft > 0) {
      timer = setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && (view === 'playing' || view === 'summary') && mode === 'exam') {
        handleFinish();
    }
    return () => clearInterval(timer);
  }, [timeLeft, view, mode]);

  const quizFilterOptions: FilterOption[] = [
    {
        label: 'Diagrams Only',
        subLabel: 'Visual Questions',
        icon: ImageIcon,
        isActive: onlyDiagrams,
        onClick: () => setOnlyDiagrams(!onlyDiagrams),
        colorTheme: 'rose'
    }
  ];

  // --- CONFIG VIEW ---
  if (view === 'config') {
    const filtersActive = selectedCategories.length > 0 || (onlyDiagrams && mode !== 'atlas');

    return (
      <div className="h-full w-full flex items-center justify-center p-4 bg-slate-50/50 pb-32 md:pb-4">
          <div className="w-full max-w-2xl bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden animate-scale-in flex flex-col max-h-[75vh] md:max-h-[90vh]">
            <div className="bg-slate-900 p-6 md:p-8 relative overflow-hidden shrink-0">
                <div className="relative z-10">
                    <h2 className="text-2xl md:text-3xl font-black text-white font-display tracking-tight">Exam Configuration</h2>
                    <p className="text-rose-500 text-xs font-bold uppercase tracking-[0.2em] mt-1">Anatomy and Physiology OT</p>
                </div>
                <div className="absolute right-0 top-0 w-64 h-64 bg-rose-500/10 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
            </div>

            <div className="flex-1 p-6 md:p-8 space-y-4 overflow-y-auto custom-scrollbar">
                <div className="grid grid-cols-2 gap-3">
                    <button 
                        onClick={() => setMode('exam')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'exam' ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'exam' ? 'bg-rose-100 text-rose-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Clock size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'exam' ? 'text-rose-900' : 'text-slate-900'}`}>Exam</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Strict Timing</p>
                    </button>

                    <button 
                        onClick={() => setMode('study')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'study' ? 'border-indigo-200 bg-indigo-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'study' ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-50 text-slate-400'}`}>
                            <Zap size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'study' ? 'text-indigo-900' : 'text-slate-900'}`}>Study</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Instant Feedback</p>
                    </button>

                    <button 
                        onClick={() => setMode('vault')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'vault' ? 'border-amber-200 bg-amber-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'vault' ? 'bg-amber-100 text-amber-600' : 'bg-slate-50 text-slate-400'}`}>
                            <AlertTriangle size={18} />
                        </div>
                        <div className="flex justify-between items-center">
                            <h3 className={`font-bold text-sm ${mode === 'vault' ? 'text-amber-900' : 'text-slate-900'}`}>Smart Review</h3>
                            {mistakes.length > 0 && <span className="bg-amber-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-md">{mistakes.length}</span>}
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Fix Mistakes</p>
                    </button>

                    <button 
                        onClick={() => setMode('atlas')} 
                        className={`p-4 rounded-2xl border-2 text-left transition-all ${mode === 'atlas' ? 'border-teal-200 bg-teal-50' : 'border-slate-100 bg-white hover:border-slate-200'}`}
                    >
                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center mb-3 ${mode === 'atlas' ? 'bg-teal-100 text-teal-600' : 'bg-slate-50 text-slate-400'}`}>
                            <MapIcon size={18} />
                        </div>
                        <h3 className={`font-bold text-sm ${mode === 'atlas' ? 'text-teal-900' : 'text-slate-900'}`}>Atlas Mode</h3>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1">Visual Lab</p>
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <button 
                        onClick={() => setIsFilterOpen(true)}
                        className={`p-4 rounded-2xl border-2 text-left transition-all flex items-center justify-between group ${filtersActive ? 'border-rose-200 bg-rose-50' : 'border-slate-100 bg-slate-50 hover:bg-white hover:border-slate-200'}`}
                    >
                        <div className="flex items-center gap-3 overflow-hidden">
                            <div className={`p-2 rounded-lg ${filtersActive ? 'bg-rose-100 text-rose-600' : 'bg-white border border-slate-200 text-slate-400 group-hover:text-rose-500'}`}>
                                <Filter size={16}/>
                            </div>
                            <div className="flex flex-col text-left min-w-0">
                                <span className={`text-[10px] font-black uppercase tracking-wider ${filtersActive ? 'text-rose-400' : 'text-slate-400'}`}>Filters</span>
                                <span className={`font-bold text-xs truncate ${filtersActive ? 'text-rose-900' : 'text-slate-700'}`}>
                                    {selectedCategories.length > 0 ? `${selectedCategories.length} Chapters` : 'Default Pool'}
                                </span>
                            </div>
                        </div>
                        <ChevronRight size={16} className={`${filtersActive ? 'text-rose-400' : 'text-slate-400'} group-hover:translate-x-1 transition-transform shrink-0`} />
                    </button>

                    <div className="p-4 rounded-2xl border border-slate-200 bg-slate-50 flex flex-col justify-center gap-2">
                        <div className="flex justify-between items-center">
                            <span className="text-[10px] font-black uppercase text-slate-400 tracking-wider">Question Limit</span>
                            <span className="font-bold text-xs text-slate-900 bg-white px-2 py-1 rounded border border-slate-200">{questionLimit}</span>
                        </div>
                        <input 
                            type="range" 
                            min={Math.min(1, currentPoolSize)}
                            max={currentPoolSize} 
                            step="1" 
                            value={questionLimit || 0}
                            onChange={(e) => setQuestionLimit(parseInt(e.target.value))}
                            disabled={currentPoolSize === 0}
                            className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-slate-900 hover:accent-rose-600 transition-all"
                        />
                    </div>
                </div>
            </div>

            <div className="p-4 md:p-6 border-t border-slate-100 bg-white shrink-0">
                <button 
                    onClick={startSession}
                    disabled={currentPoolSize === 0}
                    className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-rose-600 transition-all shadow-xl hover:shadow-rose-200 active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                >
                    Start Exam <ChevronRight size={16} />
                </button>
            </div>
          </div>

          <FilterModal
            isOpen={isFilterOpen}
            onClose={() => setIsFilterOpen(false)}
            categories={categories}
            selectedCategories={selectedCategories}
            onToggleCategory={(cat) => setSelectedCategories(prev => prev.includes(cat) ? prev.filter(c => c !== cat) : [...prev, cat])}
            onClearAll={() => { setSelectedCategories([]); setOnlyDiagrams(false); }}
            mainOptions={quizFilterOptions}
            title="Exam Settings"
          />
      </div>
    );
  }

  // --- PLAYING VIEW ---
  const currentQ = questions[currentQIndex];
  if (view === 'playing' && currentQ) {
    const isExam = mode === 'exam';
    const isAtlasMode = mode === 'atlas';
    const isStudy = mode === 'study' || mode === 'vault' || isAtlasMode; 
    const showFeedback = isStudy && currentQ.userAnswer; 

    // --- ATLAS MODE (SPLIT LAYOUT) ---
    if (isAtlasMode) {
        return (
            <div className="h-full w-full flex flex-col md:flex-row bg-slate-950 overflow-hidden relative">

               {/* 1. Image Stage (Top on Mobile, Left on Desktop) */}
               <div className="flex-1 relative flex items-center justify-center bg-black/40 overflow-hidden md:h-full h-[40vh]">
                  {/* Floating Controls */}
                  <div className="absolute top-4 left-4 z-20 flex gap-2">
                     <button onClick={() => setCurrentQIndex(c => Math.max(0, c - 1))} disabled={currentQIndex === 0} className="w-10 h-10 rounded-full bg-white/10 backdrop-blur text-white flex items-center justify-center disabled:opacity-30 hover:bg-white/20 transition-all border border-white/10">
                        <ChevronLeft size={20} />
                     </button>
                  </div>

                  {/* The Image */}
                  {currentQ.data.questionImage ? (
                      <div className="w-full h-full p-4 flex items-center justify-center cursor-zoom-in" onClick={() => onImageClick?.(currentQ.data.questionImage!)}>
                        <img 
                            src={cleanImageUrl(currentQ.data.questionImage)} 
                            className="max-w-full max-h-full object-contain drop-shadow-2xl" 
                            alt="Anatomical Figure"
                        />
                      </div>
                  ) : (
                      <div className="text-white/30 font-black uppercase tracking-widest text-xs flex flex-col items-center gap-3">
                          <ImageIcon size={48} />
                          <span>No Diagram Available</span>
                      </div>
                  )}

                  {/* Zoom Hint */}
                  <button onClick={() => onImageClick?.(currentQ.data.questionImage!)} className="absolute bottom-4 right-4 bg-black/50 text-white px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-widest border border-white/20 backdrop-blur-md flex items-center gap-2 hover:bg-white/10 transition-all">
                      <Maximize2 size={12} /> Inspect
                  </button>
               </div>

               {/* 2. Question Panel (Bottom on Mobile, Right on Desktop) */}
               <div className="w-full md:w-[450px] lg:w-[500px] shrink-0 bg-white flex flex-col z-20 shadow-[0_-10px_40px_rgba(0,0,0,0.5)] md:shadow-none md:border-l border-slate-900 rounded-t-[2rem] md:rounded-none overflow-hidden relative -mt-6 md:mt-0">

                  {/* Panel Header */}
                  <div className="p-5 md:p-6 border-b border-slate-100 flex justify-between items-center bg-white sticky top-0 z-10">
                     <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-slate-900 text-white rounded-xl flex items-center justify-center font-black text-sm shadow-lg">
                            {currentQIndex + 1}
                        </div>
                        <div>
                            <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest block">Atlas Station</span>
                            <span className="text-xs font-bold text-slate-900">Visual Identification</span>
                        </div>
                     </div>
                     <button onClick={goToSummary} className="p-2 text-slate-400 hover:text-slate-900 transition-colors">
                        <ListChecks size={20} />
                     </button>
                  </div>

                  {/* Scrollable Content */}
                  <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-slate-50/50">
                     {/* Question Text */}
                     <div className="mb-8">
                        <h2 className="text-lg md:text-xl font-black text-slate-900 leading-snug" dangerouslySetInnerHTML={{ __html: currentQ.data.questionText.replace(/In the diagram,?\s*/i, '') }} />
                     </div>

                     {/* Options */}
                     <div className="grid gap-3">
                        {currentQ.options.map((opt, i) => {
                            const isSelected = currentQ.userAnswer === opt;
                            let containerClass = "bg-white border-slate-200 text-slate-600 hover:border-slate-300";
                            let iconClass = "bg-slate-100 text-slate-400";
                            let iconContent: React.ReactNode = String.fromCharCode(65 + i);

                            if (showFeedback) {
                                if (opt === currentQ.correctOption) {
                                    containerClass = "bg-emerald-50 border-emerald-500 text-emerald-900 shadow-sm";
                                    iconClass = "bg-emerald-500 text-white";
                                    iconContent = <Check size={14} />;
                                } else if (isSelected) {
                                    containerClass = "bg-rose-50 border-rose-500 text-rose-900 shadow-sm";
                                    iconClass = "bg-rose-500 text-white";
                                    iconContent = <X size={14} />;
                                } else {
                                    containerClass = "opacity-50 bg-slate-50 border-slate-100";
                                }
                            } else if (isSelected) {
                                containerClass = "bg-slate-900 border-slate-900 text-white shadow-lg";
                                iconClass = "bg-white/20 text-white";
                            }

                            return (
                                <button 
                                    key={i}
                                    onClick={() => handleOptionSelect(opt)}
                                    className={`w-full p-4 rounded-xl border-2 flex items-center gap-4 text-left transition-all group active:scale-[0.98] ${containerClass}`}
                                >
                                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center font-bold text-xs shrink-0 transition-colors ${iconClass}`}>
                                        {iconContent}
                                    </div>
                                    <span className="font-bold text-sm" dangerouslySetInnerHTML={{ __html: opt }} />
                                </button>
                            );
                        })}
                     </div>

                     {/* Rationale */}
                     {showFeedback && (
                        <div className="mt-6 p-5 bg-white border border-slate-200 rounded-2xl shadow-sm animate-in slide-in-from-bottom-2">
                            <div className="flex items-center gap-2 mb-2 text-indigo-600">
                                <Scan size={16} />
                                <span className="text-[10px] font-black uppercase tracking-widest">Clinical Analysis</span>
                            </div>
                            <p className="text-sm text-slate-600 leading-relaxed font-medium" dangerouslySetInnerHTML={{ __html: currentQ.data.explanation || "Correct anatomical identification." }} />
                        </div>
                     )}
                  </div>

                  {/* Footer */}
                  <div className="p-4 border-t border-slate-200 bg-white">
                     <button 
                        onClick={() => currentQIndex < questions.length - 1 ? setCurrentQIndex(c => c + 1) : goToSummary()}
                        className="w-full py-4 bg-slate-900 text-white rounded-xl font-black uppercase text-xs tracking-widest hover:bg-emerald-600 transition-all shadow-xl active:scale-95 flex items-center justify-center gap-2"
                     >
                        {currentQIndex < questions.length - 1 ? (
                            <>Next Specimen <ChevronRight size={16} /></>
                        ) : (
                            <>Complete Lab <ListChecks size={16} /></>
                        )}
                     </button>
                  </div>
               </div>
            </div>
         );
    }

    // --- STANDARD LAYOUT (For Exam/Study modes) ---
    return (
      <div className="h-full flex flex-col bg-white relative">

        {notification.show && (
            <div className="absolute top-20 left-0 right-0 flex justify-center z-50 pointer-events-none animate-in fade-in slide-in-from-top-4">
                <div className={`px-6 py-3 rounded-full shadow-2xl border-2 flex items-center gap-3 font-bold text-xs uppercase tracking-widest ${
                    notification.type === 'add' 
                    ? 'bg-rose-500 text-white border-white' 
                    : 'bg-emerald-500 text-white border-white'
                }`}>
                    {notification.type === 'add' ? (
                        <>
                            <AlertTriangle size={16} className="fill-current text-white" />
                            <span>Added to Smart Review</span>
                        </>
                    ) : (
